// src/pages/admin/AdminDashboard.js
import React, { useEffect, useState } from "react";
import {
  AppBar,
  Toolbar,
  Typography,
  Container,
  Paper,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Button,
  Dialog,
  DialogTitle,
  DialogContent,
  Card,
  CardMedia,
  CardActions,
  Box,
  Stack,
} from "@mui/material";
import {
  getPendingCaptains,
  approveRider as approveCaptain,
  rejectRider as rejectCaptain,
} from "../../services/api";


export default function AdminDashboard() {
  const [pendingCaptains, setPendingCaptains] = useState([]);
  const [selectedRider, setSelectedRider] = useState(null);
  const [selectedDocuments, setSelectedDocuments] = useState([]);
  const [openDocsModal, setOpenDocsModal] = useState(false);

  // Fetch pending captains
  useEffect(() => {
    const fetchData = async () => {
      try {
        const res = await getPendingCaptains();
        setPendingCaptains(res?.data?.data || []);
      } catch (err) {
        console.error("Error fetching captains:", err);
      }
    };
    fetchData();
  }, []);

  // Handle approve
  const handleApprove = async (id) => {
    try {
      await approveCaptain(id);
      setPendingCaptains((prev) =>
        prev.filter((captain) => captain._id !== id)
      );
    } catch (err) {
      console.error("Error approving:", err);
    }
  };

  // Handle reject
  const handleReject = async (id) => {
    try {
      await rejectCaptain(id);
      setPendingCaptains((prev) =>
        prev.filter((captain) => captain._id !== id)
      );
    } catch (err) {
      console.error("Error rejecting:", err);
    }
  };

  // Handle view documents
  const handleViewDocuments = (rider) => {
    setSelectedRider(rider);
    let docs = rider?.documents || [];
    // Normalize docs to array
    if (!Array.isArray(docs)) docs = Object.values(docs);
    setSelectedDocuments(docs);
    setOpenDocsModal(true);
  };

  // Close modal
  const handleCloseDocuments = () => {
    setSelectedRider(null);
    setSelectedDocuments([]);
    setOpenDocsModal(false);
  };

  return (
    <>
      <AppBar position="static">
        <Toolbar>
          <Typography variant="h6">Admin Dashboard</Typography>
        </Toolbar>
      </AppBar>

      <Container sx={{ mt: 4 }}>
        <Paper sx={{ p: 3 }}>
          <Typography variant="h5" gutterBottom>
            Pending Details
          </Typography>
          <TableContainer>
            <Table>
              <TableHead>
                <TableRow>
                  <TableCell><strong>Name</strong></TableCell>
                  <TableCell><strong>Email</strong></TableCell>
                  <TableCell><strong>Mobile</strong></TableCell>
                  <TableCell><strong>Role</strong></TableCell>
                  <TableCell><strong>Documents</strong></TableCell>
                  <TableCell><strong>Actions</strong></TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {pendingCaptains.map((rider) => (
                  <TableRow key={rider._id}>
                    <TableCell>{rider.fullName}</TableCell>
                    <TableCell>{rider.email}</TableCell>
                    <TableCell>{rider.mobile}</TableCell>
                    <TableCell>{rider.role}</TableCell>
                    <TableCell>
                      <Button
                        variant="outlined"
                        size="small"
                        onClick={() => handleViewDocuments(rider)}
                      >
                        View Documents
                      </Button>
                    </TableCell>
                    <TableCell>
                      <Stack direction="row" spacing={1}>
                        <Button
                          variant="contained"
                          color="success"
                          size="small"
                          onClick={() => handleApprove(rider._id)}
                        >
                          Approve
                        </Button>
                        <Button
                          variant="contained"
                          color="error"
                          size="small"
                          onClick={() => handleReject(rider._id)}
                        >
                          Reject
                        </Button>
                      </Stack>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </TableContainer>
        </Paper>
      </Container>

      {/* Documents Modal */}
      <Dialog
        open={openDocsModal}
        onClose={handleCloseDocuments}
        maxWidth="md"
        fullWidth
      >
        <DialogTitle>
          Rider Details {selectedRider?.fullName ? `- ${selectedRider.fullName}` : ""}
        </DialogTitle>
        <DialogContent dividers>
          {selectedRider && (
            <Box mb={3}>
              <Typography><strong>Name:</strong> {selectedRider.fullName}</Typography>
              <Typography><strong>Email:</strong> {selectedRider.email}</Typography>
              <Typography><strong>Mobile:</strong> {selectedRider.mobile}</Typography>
              <Typography><strong>Role:</strong> {selectedRider.role}</Typography>
              <Typography><strong>Status:</strong> {selectedRider.approvalStatus}</Typography>
              <Typography>
                <strong>Created At:</strong>{" "}
                {selectedRider.createdAt ? new Date(selectedRider.createdAt).toLocaleString() : "-"}
              </Typography>
            </Box>
          )}

          <Typography variant="h6" gutterBottom>
            Documents
          </Typography>

          {(!selectedDocuments || selectedDocuments.length === 0) ? (
            <Typography>No documents uploaded.</Typography>
          ) : (
            <Stack spacing={2} direction="row" flexWrap="wrap">
              {selectedDocuments.map((doc, idx) => {
                const url =
                  doc?.url || doc?.location || doc?.secure_url || doc?.path || doc;
                const isImage = /\.(jpe?g|png|gif|webp)$/i.test(url || "");
                return (
                  <Card key={idx} sx={{ width: 250 }}>
                    {isImage ? (
                      <CardMedia
                        component="img"
                        height="180"
                        image={url}
                        alt={`Document ${idx + 1}`}
                        sx={{ objectFit: "contain" }}
                      />
                    ) : (
                      <Box
                        sx={{
                          height: 180,
                          display: "flex",
                          alignItems: "center",
                          justifyContent: "center",
                          bgcolor: "#f5f5f5",
                        }}
                      >
                        <Typography>Document {idx + 1}</Typography>
                      </Box>
                    )}
                    <CardActions>
                      <Button size="small" onClick={() => window.open(url, "_blank")}>
                        View
                      </Button>
                    </CardActions>
                  </Card>
                );
              })}
            </Stack>
          )}
        </DialogContent>
      </Dialog>
    </>
  );
}														//this admin documents view code ok
